/* ---------- 音同字索引（用於「找錯字」題型自動產生錯別字） ---------- */
const SOUND = {};   // 含調注音 -> Set(字)
const BARE = {};    // 去調注音 -> Set(字)
const CHAR_Z = {};  // 字 -> 注音（取第一次出現，用於找錯字的注音對照）
const ALLCHARS = (() => {
  const s = new Set();
  for (const d of DATA) {
    d.w.split("").forEach((ch, i) => {
      const z = d.z[i];
      (SOUND[z] || (SOUND[z] = new Set())).add(ch);
      const b = z.replace(/[ˊˇˋ˙]/g, "");
      (BARE[b] || (BARE[b] = new Set())).add(ch);
      if (!CHAR_Z[ch]) CHAR_Z[ch] = z;
      s.add(ch);
    });
  }
  return [...s];
})();
const pickRand = (arr) => arr[Math.floor(Math.random() * arr.length)];

