              {favOnly && <StateChip label="★ 只看收藏" onClear={() => setFavOnly(false)} />}
              {theme && <StateChip label={`${THEMES.find(t => t.key === theme).emoji} ${THEMES.find(t => t.key === theme).label}`} onClear={() => setTheme(null)} />}
