            {onFav && (
              <button onClick={() => onFav(item.w)} title={isFav ? "取消收藏" : "收藏這個成語"} style={{ cursor: "pointer", border: "none", background: "transparent", fontSize: 24, lineHeight: 1, color: isFav ? C.gold : C.line, padding: "0 4px" }}>{isFav ? "★" : "☆"}</button>
            )}
