const GUIDE_STEPS = [
  { emoji: "👋", title: "歡迎來到成語小學堂", desc: "這裡有 5000 個成語，每個都有注音、意思，還能聽老師念給你聽！" },
  { emoji: "☝️", title: "上下滑動看成語", desc: "在「學習」頁上下滑動，就能一個接一個認識成語。" },
  { emoji: "🔊", title: "點喇叭聽讀音", desc: "按下「聽讀音」，會用標準國語念成語和意思給你聽。" },
  { emoji: "🏷️", title: "用主題和課程探索", desc: "可以挑「課程」一課一課學，或用「主題」找動物、數字、季節的成語。" },
  { emoji: "⭐", title: "收藏、接龍、闖關測驗", desc: "點 ☆ 收藏喜歡的成語；還能玩「接龍」、做「測驗」考考自己！" },
];
function Onboarding({ onDone }) {
  const [step, setStep] = useState(0);
  const last = step === GUIDE_STEPS.length - 1;
  const s = GUIDE_STEPS[step];
  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 80, background: "rgba(43,37,34,.55)", display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
      <div style={{ width: "100%", maxWidth: 360, background: C.paper, borderRadius: 22, padding: "28px 24px 20px", boxShadow: "0 24px 70px rgba(0,0,0,.3)", border: `1px solid ${C.line}`, textAlign: "center" }}>
        <div style={{ display: "flex", justifyContent: "flex-end" }}>
          <button onClick={onDone} style={{ cursor: "pointer", border: "none", background: "transparent", color: C.inkSoft, fontFamily: SANS, fontSize: 13, fontWeight: 700 }}>略過</button>
        </div>
        <div style={{ fontSize: 64, lineHeight: 1.2, margin: "6px 0 14px" }}>{s.emoji}</div>
        <div style={{ fontFamily: SERIF, fontSize: 22, fontWeight: 800, color: C.ink, marginBottom: 10 }}>{s.title}</div>
        <div style={{ fontFamily: SANS, fontSize: 15, lineHeight: 1.7, color: C.inkSoft, minHeight: 76 }}>{s.desc}</div>
        <div style={{ display: "flex", justifyContent: "center", gap: 7, margin: "16px 0 18px" }}>
          {GUIDE_STEPS.map((_, i) => (
            <span key={i} style={{ width: i === step ? 18 : 8, height: 8, borderRadius: 4, background: i === step ? C.cinnabar : C.line, transition: "width .2s" }} />
          ))}
        </div>
        <div style={{ display: "flex", gap: 10 }}>
          {step > 0 && (
            <button onClick={() => setStep(step - 1)} style={{ flex: 1, cursor: "pointer", fontFamily: SANS, fontSize: 15, fontWeight: 800, padding: "12px 0", borderRadius: 14, border: `1.5px solid ${C.line}`, background: C.card, color: C.inkSoft }}>上一步</button>
          )}
          <button onClick={() => last ? onDone() : setStep(step + 1)} style={{ flex: 2, cursor: "pointer", fontFamily: SANS, fontSize: 15, fontWeight: 800, padding: "12px 0", borderRadius: 14, border: "none", background: C.cinnabar, color: "#fff" }}>
            {last ? "開始學習 🎉" : "下一步"}
          </button>
        </div>
      </div>
    </div>
  );
}

/* ---------- 筆順動畫視窗 ---------- */
function StrokeModal({ char, onClose }) {
  const boxRef = useRef(null);
  const writerRef = useRef(null);
  const [st, setSt] = useState({ loading: true, error: false, strokes: 0 });
  const [slow, setSlow] = useState(false);

  useEffect(() => {
    let alive = true;
    setSt(s => ({ ...s, loading: true, error: false }));
    loadCharData(char).then(data => {
      if (!alive) return;
      setSt({ loading: false, error: false, strokes: data.strokes.length });
      requestAnimationFrame(() => {
        if (!alive || !boxRef.current) return;
        boxRef.current.innerHTML = "";
        try {
          const W = boxRef.current.clientWidth || 240;
          const writer = HanziWriter.create(boxRef.current, char, {
            width: W, height: W, padding: 8,
            showOutline: true, strokeColor: C.cinnabar, outlineColor: C.line, drawingColor: C.cinnabar,
            strokeAnimationSpeed: slow ? 0.5 : 1, delayBetweenStrokes: slow ? 520 : 330,
            charDataLoader: (c, onComplete) => onComplete(data),
          });
          writerRef.current = writer;
          writer.animateCharacter();
        } catch (e) {}
      });
    }).catch(() => { if (alive) setSt({ loading: false, error: true, strokes: 0 }); });
    return () => { alive = false; };
  }, [char, slow]);

  const replay = () => { try { writerRef.current && writerRef.current.animateCharacter(); } catch (e) {} };
  const grid = `linear-gradient(${C.grid},${C.grid}) center/100% 1px no-repeat,linear-gradient(${C.grid},${C.grid}) center/1px 100% no-repeat,${C.card}`;

  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(43,37,34,.5)", display: "flex", alignItems: "center", justifyContent: "center", padding: 16, zIndex: 70 }}>
      <div onClick={e => e.stopPropagation()} style={{ background: C.paper, borderRadius: 20, maxWidth: 340, width: "100%", padding: "22px 20px", boxShadow: "0 20px 60px rgba(43,37,34,.3)", border: `1px solid ${C.line}` }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
          <div style={{ fontFamily: SERIF, fontSize: 19, fontWeight: 800, color: C.ink }}>「{char}」的筆順{st.strokes > 0 && <span style={{ fontFamily: SANS, fontSize: 13, fontWeight: 700, color: C.inkSoft, marginLeft: 8 }}>共 {st.strokes} 畫</span>}</div>
          <button onClick={onClose} style={{ cursor: "pointer", border: "none", background: "transparent", fontSize: 22, color: C.inkSoft, lineHeight: 1 }}>✕</button>
        </div>
        <div style={{ width: "100%", maxWidth: 260, aspectRatio: "1 / 1", margin: "0 auto", borderRadius: 10, border: `1.5px solid ${C.grid}`, background: grid, position: "relative", overflow: "hidden" }}>
          {/* 對角輔助線（米字格） */}
          <div style={{ position: "absolute", inset: 0, pointerEvents: "none", backgroundImage: `linear-gradient(45deg, transparent calc(50% - .5px), ${C.grid} calc(50% - .5px), ${C.grid} calc(50% + .5px), transparent calc(50% + .5px)), linear-gradient(-45deg, transparent calc(50% - .5px), ${C.grid} calc(50% - .5px), ${C.grid} calc(50% + .5px), transparent calc(50% + .5px))`, opacity: .5 }} />
          <div ref={boxRef} style={{ position: "relative", width: "100%", height: "100%" }} />
          {st.loading && <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center", color: C.inkSoft, fontFamily: SANS, fontSize: 14 }}>載入中…</div>}
          {st.error && <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center", textAlign: "center", padding: 16, color: C.inkSoft, fontFamily: SANS, fontSize: 13, lineHeight: 1.7 }}>看這個字的筆順需要連網一次，看過就會記住，下次離線也能看。</div>}
        </div>
        {!st.error && (
          <div style={{ display: "flex", gap: 10, marginTop: 16, justifyContent: "center" }}>
            <button onClick={replay} style={{ cursor: "pointer", fontFamily: SANS, fontSize: 14, fontWeight: 800, padding: "9px 18px", borderRadius: 12, border: "none", background: C.cinnabar, color: "#fff" }}>↻ 重播</button>
            <button onClick={() => setSlow(v => !v)} style={{ cursor: "pointer", fontFamily: SANS, fontSize: 14, fontWeight: 800, padding: "9px 16px", borderRadius: 12, border: `1.5px solid ${slow ? C.jade : C.line}`, background: slow ? C.jade : C.card, color: slow ? "#fff" : C.inkSoft }}>🐢 慢動作{slow ? "中" : ""}</button>
          </div>
        )}
      </div>
    </div>
  );
}

/* ---------- 兒童造句：我的造句本 ---------- */
let SENTENCE_OPEN = null; // 由 App 設定
const SENTENCE_STARTERS = ["今天", "上次……的時候，", "我覺得", "如果", "老師說", "小明", "我希望"];
function SentenceModal({ item, list, onAdd, onDelete, onClose }) {
  const [text, setText] = useState("");
  const taRef = useRef(null);
  const insert = (s) => { setText(t => (t || "") + s); requestAnimationFrame(() => { try { taRef.current && taRef.current.focus(); } catch (e) {} }); };
  const save = () => { const t = text.trim(); if (!t) return; onAdd(item.w, t); setText(""); };
  const speak = (s) => { try { SPEECH_UNLOCKED = true; speakText(s); } catch (e) {} };
  const used = text.trim() && text.includes(item.w);
  const mine = list || [];
  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, background: "rgba(43,37,34,.5)", display: "flex", alignItems: "center", justifyContent: "center", padding: 16, zIndex: 75 }}>
      <div onClick={e => e.stopPropagation()} style={{ background: C.paper, borderRadius: 20, maxWidth: 440, width: "100%", maxHeight: "90vh", overflowY: "auto", padding: "22px 20px", boxShadow: "0 20px 60px rgba(43,37,34,.3)", border: `1px solid ${C.line}` }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
          <div style={{ fontFamily: SERIF, fontSize: 19, fontWeight: 800, color: C.ink }}>用「<span style={{ color: C.cinnabar }}>{item.w}</span>」造句</div>
          <button onClick={onClose} style={{ cursor: "pointer", border: "none", background: "transparent", fontSize: 22, color: C.inkSoft, lineHeight: 1 }}>✕</button>
        </div>
        <div style={{ background: C.card, border: `1.5px solid ${C.line}`, borderRadius: 12, padding: "10px 12px", marginBottom: 14 }}>
          <div style={{ fontFamily: SANS, fontSize: 12, fontWeight: 700, color: C.cinnabar, marginBottom: 4 }}>意思</div>
          <RubyText text={item.m} zs={item.mz} size={15} />
        </div>
        <div style={{ fontFamily: SANS, fontSize: 12.5, color: C.inkSoft, marginBottom: 6 }}>不知道怎麼開頭？點一下加進去：</div>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 10 }}>
          {SENTENCE_STARTERS.map(s => (
            <button key={s} onClick={() => insert(s)} style={{ cursor: "pointer", fontFamily: SANS, fontSize: 13, fontWeight: 700, color: C.inkSoft, background: C.card, border: `1.5px solid ${C.line}`, borderRadius: 16, padding: "5px 11px" }}>{s}</button>
          ))}
          <button onClick={() => insert(item.w)} style={{ cursor: "pointer", fontFamily: SERIF, fontSize: 13, fontWeight: 800, color: "#fff", background: C.cinnabar, border: `1.5px solid ${C.cinnabar}`, borderRadius: 16, padding: "5px 11px" }}>{item.w}</button>
        </div>
        <textarea ref={taRef} value={text} onChange={e => setText(e.target.value)} placeholder={`用「${item.w}」寫一句話吧！`} rows={3}
          style={{ width: "100%", boxSizing: "border-box", fontFamily: SERIF, fontSize: 16, lineHeight: 1.7, color: C.ink, background: C.card, border: `1.5px solid ${C.line}`, borderRadius: 12, padding: "10px 12px", outline: "none", resize: "vertical" }} />
        {text.trim() && !used && (
          <div style={{ fontFamily: SANS, fontSize: 12.5, color: C.gold, marginTop: 6 }}>小提醒：句子裡記得用上「{item.w}」會更棒喔～</div>
        )}
        <button onClick={save} disabled={!text.trim()} style={{ width: "100%", marginTop: 12, cursor: text.trim() ? "pointer" : "default", fontFamily: SANS, fontSize: 15, fontWeight: 800, padding: "12px 0", borderRadius: 14, border: "none", background: text.trim() ? C.cinnabar : C.line, color: "#fff" }}>＋ 存到造句本</button>
        {mine.length > 0 && (
          <div style={{ marginTop: 18 }}>
            <div style={{ fontFamily: SANS, fontSize: 13, fontWeight: 800, color: C.inkSoft, marginBottom: 8 }}>我寫過的句子（{mine.length}）</div>
            {mine.map((s, i) => (
              <div key={i} style={{ display: "flex", alignItems: "flex-start", gap: 8, background: C.card, border: `1.5px solid ${C.line}`, borderRadius: 12, padding: "10px 12px", marginBottom: 8 }}>
                <div style={{ flex: 1, fontFamily: SERIF, fontSize: 15, lineHeight: 1.7, color: C.ink }}>{s}</div>
                <button onClick={() => speak(s)} title="朗讀" style={{ cursor: "pointer", border: "none", background: "transparent", fontSize: 16, color: C.jade, padding: 2 }}>🔊</button>
                <button onClick={() => onDelete(item.w, i)} title="刪除" style={{ cursor: "pointer", border: "none", background: "transparent", fontSize: 15, color: C.inkSoft, padding: 2 }}>🗑️</button>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

export default function App() {
  const [tab, setTab] = useState("learn");
  const [progress, setProgress] = useState(emptyProgress());
  const [ready, setReady] = useState(false);
  const [detail, setDetail] = useState(null);
  const headerRef = useRef(null);
  const [headerH, setHeaderH] = useState(98);
  const [dark, setDark] = useState(false);   // 深色模式
  const [scale, setScale] = useState(1);     // 字級倍率
  const [showTools, setShowTools] = useState(false); // 學習工具面板（鈕在分頁列）
  const [showGuide, setShowGuide] = useState(false); // 第一次開啟引導
  const [strokeChar, setStrokeChar] = useState(null); // 筆順視窗
  const [sentences, setSentences] = useState({});     // 造句本 { 成語: [句子] }
  const [sentenceItem, setSentenceItem] = useState(null); // 正在造句的成語

  useEffect(() => {
    const l1 = document.createElement("link"); l1.rel = "preconnect"; l1.href = "https://fonts.googleapis.com"; document.head.appendChild(l1);
    const l2 = document.createElement("link"); l2.rel = "stylesheet";
    l2.href = "https://fonts.googleapis.com/css2?family=Noto+Sans+TC:wght@400;500;700;800;900&family=Noto+Serif+TC:wght@400;500;600;700;800;900&display=swap";
    document.head.appendChild(l2);
    const st = document.createElement("style");
    st.textContent = `*{box-sizing:border-box}button{font:inherit}html,body{margin:0}::selection{background:${C.gold}55}
      input::placeholder{color:${C.inkSoft}99}
      @media(prefers-reduced-motion:reduce){*{transition:none!important}}`;
    document.head.appendChild(st);
    return () => { [l1, l2, st].forEach(n => n.remove()); };
  }, []);

  useEffect(() => { loadProgress().then(p => { setProgress(p); setReady(true); }); }, []);
  // 第一次開啟顯示引導
  useEffect(() => {
    if (!window.storage) { setShowGuide(true); return; }
    window.storage.get("idiom-onboarded-v1").then(r => { if (!r || !r.value) setShowGuide(true); });
  }, []);
  const finishGuide = () => { setShowGuide(false); try { window.storage && window.storage.set("idiom-onboarded-v1", "1"); } catch (e) {} };
  useEffect(() => { STROKE_OPEN = (ch) => setStrokeChar(ch); return () => { STROKE_OPEN = null; }; }, []);
  useEffect(() => { SENTENCE_OPEN = (item) => setSentenceItem(item); return () => { SENTENCE_OPEN = null; }; }, []);
  // 載入造句本
  useEffect(() => {
    if (!window.storage) return;
    window.storage.get("idiom-sentences-v1").then(r => { if (r && r.value) { try { setSentences(JSON.parse(r.value) || {}); } catch (e) {} } });
  }, []);
  const saveSentences = (next) => { setSentences(next); try { window.storage && window.storage.set("idiom-sentences-v1", JSON.stringify(next)); } catch (e) {} };
  const addSentence = (w, text) => { const arr = sentences[w] ? [...sentences[w]] : []; arr.push(text); saveSentences({ ...sentences, [w]: arr }); };
  const delSentence = (w, idx) => { const arr = (sentences[w] || []).filter((_, i) => i !== idx); const next = { ...sentences }; if (arr.length) next[w] = arr; else delete next[w]; saveSentences(next); };

  // 進度匯出／匯入（換手機、給多個孩子用）
  const exportData = () => {
    const data = { app: "成語小學堂", version: 1, exportedAt: new Date().toISOString(), progress, sentences, ui: { dark, scale } };
    try {
      const blob = new Blob([JSON.stringify(data, null, 2)], { type: "application/json" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      const d = new Date(), pad = n => String(n).padStart(2, "0");
      a.href = url; a.download = `成語小學堂-進度-${d.getFullYear()}${pad(d.getMonth() + 1)}${pad(d.getDate())}.json`;
      document.body.appendChild(a); a.click(); a.remove(); setTimeout(() => URL.revokeObjectURL(url), 1000);
    } catch (e) { alert("匯出失敗，請改用截圖或稍後再試。"); }
  };
  const importData = (file) => {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      try {
        const obj = JSON.parse(reader.result);
        if (!obj || obj.app !== "成語小學堂") { alert("這個檔案看起來不是成語小學堂的進度檔。"); return; }
        if (!window.confirm("匯入會覆蓋目前的學習紀錄與造句本，確定要匯入嗎？")) return;
        if (obj.progress) { const np = { ...emptyProgress(), ...obj.progress }; setProgress(np); saveProgress(np); }
        if (obj.sentences) { setSentences(obj.sentences); try { window.storage && window.storage.set("idiom-sentences-v1", JSON.stringify(obj.sentences)); } catch (e) {} }
        if (obj.ui) {
          const dk = !!obj.ui.dark, sc = obj.ui.scale || 1;
          applyTheme(dk); setDark(dk); FS = sc; setScale(sc); saveUI({ dark: dk, scale: sc });
          const mt = document.querySelector('meta[name="theme-color"]'); if (mt) mt.setAttribute("content", dk ? DARK.paper : LIGHT.paper);
        }
        alert("匯入完成！你的成語紀錄都回來了。");
      } catch (e) { alert("匯入失敗：檔案格式不正確。"); }
    };
    reader.readAsText(file);
  };
  // 載入字級／深色偏好
  useEffect(() => {
    if (!window.storage) return;
    window.storage.get("idiom-ui-v1").then(r => {
      if (!r || !r.value) return;
      try {
        const o = JSON.parse(r.value);
        if (o.dark) { applyTheme(true); setDark(true); const mt = document.querySelector('meta[name="theme-color"]'); if (mt) mt.setAttribute("content", DARK.paper); }
        if (o.scale && o.scale !== 1) { FS = o.scale; setScale(o.scale); }
      } catch (e) {}
    });
  }, []);
  useEffect(() => {
    if (!window.speechSynthesis) return;
    refreshVoices();
    speechSynthesis.onvoiceschanged = refreshVoices;
    return () => { try { speechSynthesis.onvoiceschanged = null; speechSynthesis.cancel(); } catch (e) {} };
  }, []);
  useEffect(() => {
    const el = headerRef.current; if (!el) return;
    const u = () => setHeaderH(el.offsetHeight);
    u();
    let ro;
    if (typeof ResizeObserver !== "undefined") { ro = new ResizeObserver(u); ro.observe(el); }
    window.addEventListener("resize", u);
    return () => { if (ro) ro.disconnect(); window.removeEventListener("resize", u); };
  }, []);

  const update = useCallback((fn) => {
    setProgress(prev => { const np = fn(prev); saveProgress(np); return np; });
  }, []);
  const recordQuiz = useCallback((score, total, wrongs) => update(p => {
    const wrong = { ...p.wrong };
    wrongs.forEach(it => { wrong[it.w] = (wrong[it.w] || 0) + 1; });
    const best = !p.best || score / total > p.best.score / p.best.total ? { score, total } : p.best;
    return { ...p, wrong, best };
  }), [update]);
  // 專攻錯題：答對就把該成語移出錯題清單（答錯維持）
  const practiceWrong = useCallback((w, correct) => update(p => {
    if (!correct) return p;
    const wrong = { ...p.wrong }; delete wrong[w];
    return { ...p, wrong };
  }), [update]);
  const toggleFav = useCallback((w) => update(p => {
    const fav = { ...(p.fav || {}) };
    if (fav[w]) delete fav[w]; else fav[w] = 1;
    return { ...p, fav };
  }), [update]);
  const favSet = progress.fav || {};
  const reset = useCallback(() => { if (window.confirm("確定要清除所有學習與測驗紀錄嗎？")) update(() => emptyProgress()); }, [update]);

  const saveUI = (next) => { try { window.storage && window.storage.set("idiom-ui-v1", JSON.stringify({ dark, scale, ...next })); } catch (e) {} };
  const toggleDark = () => {
    const nd = !dark; applyTheme(nd); setDark(nd); saveUI({ dark: nd });
    const mt = document.querySelector('meta[name="theme-color"]'); if (mt) mt.setAttribute("content", nd ? DARK.paper : LIGHT.paper);
  };
  const SCALES = [1, 1.2, 1.4];
  const cycleScale = () => { const i = SCALES.indexOf(scale); const ns = SCALES[(i + 1) % SCALES.length] || 1; FS = ns; setScale(ns); saveUI({ scale: ns }); };
  const scaleLabel = scale === 1 ? "標準" : scale === 1.2 ? "大" : "特大";
  const ver = (dark ? "d" : "l") + scale; // 傳給 memo 的 IdiomPage 觸發重繪

  const TABS = [["learn", "學習"], ["quiz", "測驗"], ["dragon", "接龍"], ["progress", "進度"]];

  return (
    <div style={{ minHeight: "100dvh", background: C.paper, fontFamily: SANS, color: C.ink }}>
      <header ref={headerRef} style={{ borderBottom: `1.5px solid ${C.line}`, background: C.paper, position: "sticky", top: 0, zIndex: 30 }}>
        <div style={{ maxWidth: 760, margin: "0 auto", padding: "14px 16px", display: "flex", alignItems: "center", gap: 12 }}>
          <div style={{ width: 42, height: 42, borderRadius: 9, background: C.cinnabar, color: C.paper, fontFamily: SERIF, fontWeight: 800, fontSize: 24, display: "flex", alignItems: "center", justifyContent: "center", boxShadow: `inset 0 0 0 2px ${C.paper}, inset 0 0 0 3.5px ${C.cinnabar}` }}>語</div>
          <div>
            <div style={{ fontFamily: SERIF, fontSize: 22, fontWeight: 800, lineHeight: 1.1, color: C.ink }}>成語小學堂</div>
            <div style={{ fontFamily: SANS, fontSize: 12, color: C.inkSoft, marginTop: 2 }}>注音認字 · 理解語意 · 闖關測驗</div>
          </div>
          <div style={{ marginLeft: "auto", display: "flex", gap: 8, alignItems: "center" }}>
            <button onClick={cycleScale} title="調整字級大小" style={{
              cursor: "pointer", fontFamily: SANS, fontSize: 13, fontWeight: 800, color: C.inkSoft,
              padding: "6px 10px", borderRadius: 12, border: `1.5px solid ${C.line}`, background: C.card,
              display: "inline-flex", alignItems: "center", gap: 5, lineHeight: 1,
            }}><span style={{ fontSize: 16 }}>🔤</span>{scaleLabel}</button>
            <button onClick={toggleDark} title={dark ? "切換亮色模式" : "切換深色模式（護眼）"} style={{
              cursor: "pointer", fontSize: 18, lineHeight: 1, width: 38, height: 34, borderRadius: 12,
              border: `1.5px solid ${C.line}`, background: C.card, display: "inline-flex", alignItems: "center", justifyContent: "center",
            }}>{dark ? "☀️" : "🌙"}</button>
          </div>
        </div>
        <div style={{ maxWidth: 760, margin: "0 auto", padding: "0 16px", display: "flex", gap: 4 }}>
          {TABS.map(([k, label]) => (
            <button key={k} onClick={() => { if ((k === "learn" || k === "dragon") && window.speechSynthesis) SPEECH_UNLOCKED = true; if (k !== "learn") setShowTools(false); setTab(k); }} style={{
              cursor: "pointer", fontFamily: SANS, fontSize: 15, fontWeight: 700, padding: "10px 16px",
              border: "none", background: "transparent", color: tab === k ? C.cinnabar : C.inkSoft,
              borderBottom: `3px solid ${tab === k ? C.cinnabar : "transparent"}`, marginBottom: -1.5,
            }}>{label}</button>
          ))}
          {tab === "learn" && (
            <button onClick={() => setShowTools(true)} title="課程、搜尋、主題、收藏、朗讀設定" style={{
              marginLeft: "auto", alignSelf: "center", cursor: "pointer", fontFamily: SANS, fontSize: 13, fontWeight: 800,
              padding: "6px 14px", borderRadius: 20, border: `1.5px solid ${C.line}`, background: C.card, color: C.inkSoft,
              display: "inline-flex", alignItems: "center", gap: 6,
            }}><span style={{ fontSize: 15 }}>⚙️</span>工具</button>
          )}
        </div>
      </header>

      <main>
        {!ready ? (
          <div style={{ textAlign: "center", color: C.inkSoft, paddingTop: 60, fontFamily: SANS }}>載入中…</div>
        ) : tab === "learn" ? (
          <LearnPage headerH={headerH} ver={ver} favSet={favSet} toggleFav={toggleFav} showTools={showTools} setShowTools={setShowTools} />
        ) : (
          <div style={{ maxWidth: 760, margin: "0 auto", padding: "20px 16px 60px" }}>
            {tab === "quiz" && <QuizPage recordQuiz={recordQuiz} openDetail={setDetail} wrongData={progress.wrong} practiceWrong={practiceWrong} />}
            {tab === "dragon" && <DragonGame openDetail={setDetail} />}
            {tab === "progress" && <ProgressPage progress={progress} reset={reset} openDetail={setDetail} replayGuide={() => setShowGuide(true)} sentences={sentences} delSentence={delSentence} exportData={exportData} importData={importData} />}
          </div>
        )}
      </main>

      {detail && <DetailModal item={detail} onClose={() => setDetail(null)} isFav={!!favSet[detail.w]} onFav={toggleFav} />}
      {showGuide && <Onboarding onDone={finishGuide} />}
      {strokeChar && <StrokeModal char={strokeChar} onClose={() => setStrokeChar(null)} />}
      {sentenceItem && <SentenceModal item={sentenceItem} list={sentences[sentenceItem.w]} onAdd={addSentence} onDelete={delSentence} onClose={() => setSentenceItem(null)} />}
    </div>
  );
}
